package io.harbor.textd.core;

final class WorkerBindings {
    private static final ThreadLocal<DispatchBinding> ACTIVE = new ThreadLocal<>();

    private WorkerBindings() {
    }

    static DispatchBinding current(GenerationRegistry registry) {
        GenerationLease activeLease = registry.active();
        DispatchBinding binding = ACTIVE.get();
        if (binding == null) {
            DispatchBinding created = new DispatchBinding(activeLease);
            ACTIVE.set(created);
            return created;
        }

        if (!binding.matches(activeLease)) {
            DispatchBinding replacement = new DispatchBinding(activeLease);
            ACTIVE.set(replacement);
            return replacement;
        }

        return binding;
    }

    static void releaseCurrent() {
        DispatchBinding binding = ACTIVE.get();
        if (binding != null) {
            binding.close();
            ACTIVE.remove();
        }
    }
}
